from assay_engine.methodology.fence import Measurement, Interpretation
from assay_engine._frozen import freeze, FrozenDict
import collections.abc

class DuckMap:
    """A duck-typed mapping: exposes items()/keys()/__getitem__/__iter__,
    but is NOT registered as collections.abc.Mapping."""
    def __init__(self, d):
        self._d = dict(d)
    def items(self):
        return self._d.items()
    def keys(self):
        return self._d.keys()
    def __getitem__(self, k):
        return self._d[k]
    def __iter__(self):
        return iter(self._d)
    def __len__(self):
        return len(self._d)

