from assay_engine._frozen import freeze, FrozenDict, freeze_mapping

class DuckMap:
    def __init__(self, d): self._d = dict(d)
    def items(self): return self._d.items()
    def keys(self): return self._d.keys()
    def __getitem__(self, k): return self._d[k]
    def __iter__(self): return iter(self._d)
    def __len__(self): return len(self._d)

# Nested inside a normal dict that DOES get frozen -> FrozenDict
outer = {'inner': DuckMap({'x': 1})}
fz = freeze(outer)
print("outer frozen type:", type(fz).__name__)
print("inner type after freeze:", type(fz['inner']).__name__)
# mutate through the frozen FrozenDict
fz['inner']._d['x'] = 999
print("mutated nested duckmap inside FrozenDict:", fz['inner']['x'])

# Is it even hashable (the claim: passes the hash() check by identity)?
try:
    h = hash(freeze(DuckMap({'x':1})))
    print("DuckMap hashable by identity:", h is not None)
